package raft

// Very small pseudocode for leader committing a log entry
func leaderAppend(entry LogEntry) bool {
    // append to leader log
    log.append(entry)
    // send AppendEntries RPCs to followers in parallel
    acks := 1 // leader itself
    for _, f := range followers {
        go func(peer Peer) {
            reply := peer.AppendEntries(&AppendArgs{Entries: []LogEntry{entry}, Term: currentTerm, PrevLogIndex: entry.Index-1, PrevLogTerm: log.termAt(entry.Index-1)})
            if reply.Success { atomic.AddInt(&acks, 1) }
        }(f)
    }
    // wait for majority (simplified, with timeout)
    if waitForQuorum(acks) {
        commitIndex = entry.Index
        apply(entry)
        return true
    }
    return false
}
